    /* ─── 🔬 TAB MÉTHODES AVANCÉES (stats.php) ─── */
    'stats_adv_tab'              => ['ar'=>'الطرق المتقدّمة', 'fr'=>'Méthodes avancées', 'en'=>'Advanced methods'],
    'stats_adv_concept_title'    => ['ar'=>'المفهوم — طرق متعدّدة المتغيّرات', 'fr'=>'Concept — Méthodes multivariées', 'en'=>'Concept — Multivariable methods'],
    'stats_adv_concept_body'     => [
        'ar'=>'هذا التبويب يجمع التحليلات المتقدّمة المتاحة عبر مكتبة <b>BiostatPHP</b>: الانحدار اللوجستي المتعدّد V1 (Hosmer & Lemeshow)، النموذج الخطي المعمَّم المختلط GLMM مع تأثير عشوائي للمدرسة، معادلات التقدير المعمَّمة GEE مع cluster-robust SE، التعويض المتعدّد MICE مع قواعد Rubin، منحنى ROC مع AUC، اختبار ملاءمة Hosmer-Lemeshow، وتصحيح Benjamini-Hochberg لمعدّل الاكتشاف الكاذب. <b>الهدف</b>: التحقّق من متانة التقديرات وضبط التشويش العنقودي ومعالجة البيانات الناقصة.',
        'fr'=>'Cet onglet rassemble les analyses avancées disponibles via la bibliothèque <b>BiostatPHP</b> : régression logistique multivariée V1 (Hosmer & Lemeshow), GLMM avec effet aléatoire école, GEE avec erreurs sandwich cluster-robust, imputation multiple MICE avec règles de Rubin, courbe ROC + AUC, test d\'adéquation Hosmer-Lemeshow, et correction Benjamini-Hochberg du FDR. <b>Objectif</b> : valider la robustesse des estimations, ajuster le clustering institutionnel et gérer les données manquantes.',
        'en'=>'This tab gathers advanced analyses available through the <b>BiostatPHP</b> library: multivariable logistic regression V1 (Hosmer & Lemeshow), GLMM with school random effect, GEE with cluster-robust sandwich SE, MICE multiple imputation with Rubin\'s rules, ROC curve + AUC, Hosmer-Lemeshow goodness-of-fit, and Benjamini-Hochberg FDR correction. <b>Goal</b>: validate estimate robustness, adjust for institutional clustering, and handle missing data.'
    ],
    'stats_adv_insufficient'     => ['ar'=>'البيانات غير كافية للتحليل المتعدّد',  'fr'=>'Données insuffisantes pour l\'analyse multivariée', 'en'=>'Insufficient data for multivariable analysis'],
    'stats_adv_insufficient_msg' => ['ar'=>'تتطلّب التحليلات المتعدّدة 30 ملاحظة على الأقل مع جميع المتنبئات الستة الأساسية متوفّرة (KIDMED، النشاط، الخمول، النوم، الضغط، العمر).', 'fr'=>'Les analyses multivariées requièrent au moins 30 observations avec tous les 6 prédicteurs principaux disponibles (KIDMED, activité, sédentarité, sommeil, pression, âge).', 'en'=>'Multivariable analyses require at least 30 observations with all 6 main predictors available (KIDMED, activity, sedentariness, sleep, pressure, age).'],
    'stats_adv_insufficient_hint'=> ['ar'=>'استمرّ في جمع الاستبيانات؛ ستظهر هذه التحليلات تلقائيًا حين تتوفّر البيانات.', 'fr'=>'Continuez la collecte ; ces analyses apparaîtront automatiquement dès que les données seront suffisantes.', 'en'=>'Keep collecting data; these analyses will appear automatically once data is sufficient.'],
    'stats_adv_v1_title'         => ['ar'=>'الانحدار اللوجستي المتعدّد V1 — OR مُعدَّلة', 'fr'=>'Régression logistique multivariée V1 — OR ajustés', 'en'=>'Multivariable logistic regression V1 — Adjusted ORs'],
    'stats_adv_v1_intro'         => ['ar'=>'النموذج المعدَّل على المتغيّرات الثمانية الأساسية: KIDMED، النشاط، الخمول، النوم، الضغط، حذف الوجبات، الجنس، العمر. النتيجة: زيادة الوزن أو السمنة (IOTF).', 'fr'=>'Modèle ajusté sur les 8 prédicteurs principaux : KIDMED, activité, sédentarité, sommeil, pression, saut de repas, sexe, âge. Issue : surpoids ou obésité (IOTF).', 'en'=>'Model adjusted on the 8 main predictors: KIDMED, activity, sedentariness, sleep, pressure, meal skipping, sex, age. Outcome: overweight or obesity (IOTF).'],
    'stats_adv_v1_interp'        => ['ar'=>'كل OR يمثّل الأثر الصافي للمتغيّر بعد ضبط بقية المتغيّرات. OR > 1 = عامل خطر (أحمر)؛ OR < 1 = عامل وقاية (أخضر).', 'fr'=>'Chaque OR représente l\'effet net du prédicteur après ajustement sur les autres. OR > 1 = facteur de risque (rouge) ; OR < 1 = facteur protecteur (vert).', 'en'=>'Each OR represents the net effect of the predictor after adjusting for the others. OR > 1 = risk factor (red); OR < 1 = protective factor (green).'],
    'stats_adv_roc_title'        => ['ar'=>'منحنى ROC + AUC + اختبار Hosmer-Lemeshow للملاءمة', 'fr'=>'Courbe ROC + AUC + Test d\'adéquation Hosmer-Lemeshow', 'en'=>'ROC curve + AUC + Hosmer-Lemeshow goodness-of-fit'],
