    // ══════════════════════════════════════════════════════════
    // ABOUT.PHP — قدرات وحدود المنصة
    // ══════════════════════════════════════════════════════════
    'about_cap_title'     => ['ar'=>'قدرات المنصة وحدودها', 'fr'=>'Capacites et limites de la plateforme', 'en'=>'Platform capabilities and limitations'],
    'about_cap_intro'     => [
        'ar'=>'من باب الشفافية العلمية والأمانة الأكاديمية، نوضّح فيما يلي ما تستطيع هذه المنصة فعله وما لا تستطيعه. المنصة صُمّمت كأداة جمع بيانات وتحليل أولي، وليست بديلاً عن البرامج الإحصائية المتخصصة.',
        'fr'=>"Par souci de transparence scientifique et d'integrite academique, nous detaillons ci-dessous ce que cette plateforme peut et ne peut pas faire. Elle a ete concue comme outil de collecte et d'analyse preliminaire, non comme substitut aux logiciels statistiques specialises.",
        'en'=>'In the interest of scientific transparency and academic integrity, we detail below what this platform can and cannot do. It was designed as a data collection and preliminary analysis tool, not as a substitute for specialised statistical software.'
    ],
    'about_can_title'     => ['ar'=>'ما تستطيع المنصة فعله', 'fr'=>'Ce que la plateforme peut faire', 'en'=>'What the platform can do'],
    'about_can_1'         => ['ar'=>'جمع البيانات في الوقت الحقيقي عبر استبيان مُهيكل من 84 عنصراً مع تحقق فوري من صحة المدخلات (47 حقلاً فئوياً + 10 حقول رقمية)', 'fr'=>"Collecte de donnees en temps reel via un questionnaire structure de 84 items avec validation instantanee (47 champs categoriels + 10 champs numeriques)", 'en'=>'Real-time data collection via a structured 84-item questionnaire with instant input validation (47 categorical + 10 numeric fields)'],
    'about_can_2'         => ['ar'=>'الحساب التلقائي لـ 17 مؤشراً مشتقاً لحظة الإدخال: IMC، تصنيف IOTF (Cole 2000+2007)، KIDMED، scores النوم والنشاط والخمول والضغط والأسرة وخطر السمنة', 'fr'=>"Calcul automatique de 17 scores derives a la saisie : IMC, classification IOTF (Cole 2000+2007), KIDMED, scores sommeil/activite/sedentarite/pression/famille/risque d'obesite", 'en'=>'Automatic calculation of 17 derived scores at entry: BMI, IOTF classification (Cole 2000+2007), KIDMED, sleep/activity/sedentarity/pressure/family/obesity risk scores'],
    'about_can_3'         => ['ar'=>'التحليل الوصفي الكامل: المتوسط، الانحراف المعياري، الوسيط، التكرارات والنسب المئوية، التوزيعات', 'fr'=>'Analyse descriptive complete : moyenne, ecart-type, mediane, frequences et pourcentages, distributions', 'en'=>'Complete descriptive analysis: mean, standard deviation, median, frequencies and percentages, distributions'],
    'about_can_4'         => ['ar'=>'**اختبار 68 فرضية بيوإحصائية** آلياً موزَّعة على 10 عائلات (H1–H10): t-Welch مع correction Yates، χ² 2×2، ANOVA أحادية الاتجاه، Pearson وSpearman، OR مع IC 95% (Woolf)، مع **تصحيح Benjamini-Hochberg** للتحكم في معدل الاكتشاف الكاذب (FDR)', 'fr'=>'**Test automatique de 68 hypothèses biostatistiques** réparties en 10 familles (H1–H10) : t-Welch avec correction Yates, χ² 2×2, ANOVA à un facteur, Pearson et Spearman, OR avec IC 95% (Woolf), avec **correction Benjamini-Hochberg** pour contrôler le False Discovery Rate (FDR)', 'en'=>'**Automatic testing of 68 biostatistical hypotheses** across 10 families (H1–H10): t-Welch with Yates correction, χ² 2×2, one-way ANOVA, Pearson and Spearman, OR with 95% CI (Woolf), with **Benjamini-Hochberg correction** to control False Discovery Rate (FDR)'],
    'about_can_5'         => ['ar'=>'**انحدار لوجستي متعدد المتغيرات** (Newton-Raphson, ≤100 تكرار، tolérance 1e-6) مع OR مُعدَّلة، فاصل ثقة 95%، اختبار Hosmer-Lemeshow للملاءمة، وحساب AUC بطريقة Hanley-McNeil', 'fr'=>'**Régression logistique multivariée** (Newton-Raphson, ≤100 itérations, tolérance 1e-6) avec OR ajustés, IC 95%, test de Hosmer-Lemeshow pour la qualité d\'ajustement, et AUC calculé par méthode Hanley-McNeil', 'en'=>'**Multivariate logistic regression** (Newton-Raphson, ≤100 iterations, 1e-6 tolerance) with adjusted ORs, 95% CI, Hosmer-Lemeshow goodness-of-fit test, and AUC via Hanley-McNeil method'],
    'about_can_6'         => ['ar'=>'**تحليل خاص بالسنة الثالثة ثانوي**: 8 فرضيات (H10.1–H10.8) لدراسة تأثير الضغط الدراسي والدروس الخصوصية، مع اختبار Cochran-Armitage للاتجاه التصاعدي عبر المستويات 1AS→2AS→3AS، وجدول تقاطعي ثلاثي الأبعاد (الضغط × الوضع الوزني × المستوى)', 'fr'=>'**Analyse spécifique aux élèves de Terminale (3AS)** : 8 hypothèses (H10.1–H10.8) sur l\'impact de la pression scolaire et des cours de soutien, avec test de tendance Cochran-Armitage pour la progression 1AS→2AS→3AS, et tableau croisé tridimensionnel (pression × statut pondéral × niveau)', 'en'=>'**Grade-12 specific analysis**: 8 hypotheses (H10.1–H10.8) on academic pressure and private tutoring impact, with Cochran-Armitage trend test for 1AS→2AS→3AS progression, and 3-way cross-table (pressure × weight status × grade)'],
    'about_can_7'         => ['ar'=>'**تقرير بيوإحصائي تفاعلي محسَّن**: 6 بطاقات KPI رئيسية + 6 بطاقات خاصة بـ 3AS، 8 رسوم بيانية، Forest Plot ديناميكي للـ OR المعنوية، رسم تطوّر المؤشرات عبر المستويات، جدول قيم مفقودة مع علامات تنبيه، وسرد آلي للنتائج البارزة', 'fr'=>'**Rapport biostatistique interactif amélioré** : 6 KPI principaux + 6 KPI focus 3AS, 8 graphiques, Forest Plot dynamique des OR significatifs, courbe d\'évolution par niveau, tableau de données manquantes avec flags, narration automatique des résultats saillants', 'en'=>'**Enhanced interactive biostatistical report**: 6 main KPI cards + 6 Grade-12 focus cards, 8 charts, dynamic Forest Plot, indicators-by-grade evolution chart, missing-data table with flags, automatic narrative of key findings'],
    'about_can_8'         => ['ar'=>'خريطة تفاعلية لولاية الشلف مع عرض المؤشرات حسب الدائرة', 'fr'=>'Carte interactive de la wilaya de Chlef avec affichage des indicateurs par daira', 'en'=>'Interactive map of Chlef province with per-district indicator display'],
    'about_can_9'         => ['ar'=>'واجهة ثلاثية اللغات (عربية، فرنسية، إنجليزية) مع تبديل فوري', 'fr'=>'Interface trilingue (arabe, francais, anglais) avec basculement instantane', 'en'=>'Trilingual interface (Arabic, French, English) with instant switching'],
    'about_can_10'        => ['ar'=>'تصدير البيانات بصيغة CSV لاستيرادها في SPSS أو R أو Excel، مع **حماية أمنية شاملة**: CSRF tokens، rate limiting (1 إرسال/IP/30 ثانية)، journal d\'audit كامل، وتحقّق strict من قيم المدخلات', 'fr'=>'Export CSV des données pour SPSS, R ou Excel, avec **sécurité renforcée** : tokens CSRF, rate limiting (1 envoi/IP/30 sec), journal d\'audit complet, et validation stricte des entrées', 'en'=>'CSV data export for SPSS, R, or Excel, with **enhanced security**: CSRF tokens, rate limiting (1 submission/IP/30 sec), complete audit log, and strict input validation'],
    'about_cannot_title'  => ['ar'=>'ما لا تستطيع المنصة فعله (يتطلب SPSS أو R)', 'fr'=>'Ce que la plateforme ne peut pas faire (necessite SPSS ou R)', 'en'=>'What the platform cannot do (requires SPSS or R)'],
    'about_cannot_1'      => ['ar'=>'اختبار الطبيعية (Shapiro-Wilk, Kolmogorov-Smirnov) — شرط أساسي قبل الاختبارات المعلمية لتحديد ما إذا كان t-test صالحاً أم يجب استخدام Mann-Whitney', 'fr'=>'Test de normalite (Shapiro-Wilk, Kolmogorov-Smirnov) — prerequis aux tests parametriques pour determiner si le t-test est valide ou s\'il faut utiliser Mann-Whitney', 'en'=>"Normality testing (Shapiro-Wilk, Kolmogorov-Smirnov) — prerequisite for parametric tests to determine whether t-test is valid or Mann-Whitney should be used"],
    'about_cannot_2'      => ['ar'=>'اختبارات Post-hoc (Tukey HSD, Bonferroni) بعد ANOVA — لتحديد أي مجموعتين بالضبط تختلفان معنوياً', 'fr'=>'Tests post-hoc (Tukey HSD, Bonferroni) apres ANOVA — pour identifier quels groupes different significativement', 'en'=>'Post-hoc tests (Tukey HSD, Bonferroni) after ANOVA — to identify which specific groups differ significantly'],
    'about_cannot_3'      => ['ar'=>'الانحدار اللوجستي **متعدد المتغيرات الكامل** بمعالجة متغيّرات تابعة متعدّدة المستويات (multinomial)، مع **محاذاة كاملة لـ SPSS** على كل صياغات IC95 (likelihood-ratio bands بدلاً من Wald). المنصة الحالية تستخدم Wald + IC من Hessian (مقبول علميًا، لكن SPSS أكثر مرونة في nuances الحدّية)', 'fr'=>'Régression logistique **multivariée multinomiale** (variable dépendante à >2 catégories), avec **alignement total à SPSS** sur toutes les formulations d\'IC95 (likelihood-ratio bands au lieu de Wald). La plateforme actuelle utilise Wald + IC de la Hessienne (scientifiquement acceptable, mais SPSS offre plus de nuances aux limites)', 'en'=>'**Multinomial logistic regression** (dependent variable with >2 categories), with **full SPSS alignment** on all CI95 formulations (likelihood-ratio bands instead of Wald). Current platform uses Wald + Hessian-based CI (scientifically acceptable, but SPSS offers more nuance at boundaries)'],
    'about_cannot_4'      => ['ar'=>'الانحدار الخطي المتعدد مع VIF (كشف التداخل الخطي) وتحليل الرواسب (Residuals) للتحقق من افتراضات النموذج', 'fr'=>'Regression lineaire multiple avec VIF (detection de multicolinearite) et analyse des residus pour verifier les hypotheses du modele', 'en'=>'Multiple linear regression with VIF (multicollinearity detection) and residual analysis to verify model assumptions'],
    'about_cannot_5'      => ['ar'=>'تحليل العوامل (Factor Analysis) والتحليل العنقودي (Cluster Analysis) — أدوات استكشافية متقدمة لتحديد الأنماط الخفية في البيانات', 'fr'=>'Analyse factorielle et analyse en clusters — outils exploratoires avances pour identifier les patterns caches dans les donnees', 'en'=>'Factor analysis and cluster analysis — advanced exploratory tools for identifying hidden patterns in data'],
    'about_cannot_6'      => ['ar'=>'الاختبارات اللامعلمية البديلة (Mann-Whitney, Kruskal-Wallis) — ضرورية عندما لا يتحقق شرط التوزيع الطبيعي', 'fr'=>'Tests non parametriques alternatifs (Mann-Whitney, Kruskal-Wallis) — necessaires quand la normalite n\'est pas verifiee', 'en'=>'Alternative non-parametric tests (Mann-Whitney, Kruskal-Wallis) — necessary when normality assumption is not met'],
    'about_cannot_7'      => ['ar'=>'الرسوم البيانية عالية الجودة القابلة للتخصيص الكامل والمطابقة لمعايير النشر في المجلات العلمية المحكّمة', 'fr'=>'Graphiques haute qualite entierement personnalisables conformes aux normes de publication des revues scientifiques', 'en'=>'High-quality, fully customisable graphics conforming to peer-reviewed journal publication standards'],
    'about_recommend'     => ['ar'=>'المنهجية الموصى بها', 'fr'=>'Methodologie recommandee', 'en'=>'Recommended methodology'],
    'about_recommend_text' => [
        'ar'=>'تُستخدم هذه المنصة لجمع البيانات والمراقبة اليومية والتحليل الأولي واكتشاف الاتجاهات. ثم تُصدَّر البيانات بصيغة CSV وتُستورد في SPSS (أو R) للتحليل النهائي المعمّق الذي يظهر في فصل النتائج بالمذكرة. هذا المنهج المزدوج (منصة رقمية + برنامج إحصائي) هو ما تعتمده الدراسات الوبائية الكبرى.',
        'fr'=>"Cette plateforme est utilisee pour la collecte, le suivi quotidien, l'analyse preliminaire et la detection des tendances. Les donnees sont ensuite exportees en CSV et importees dans SPSS (ou R) pour l'analyse finale approfondie presentee dans le chapitre Resultats. Cette double approche (plateforme numerique + logiciel statistique) est celle adoptee par les grandes etudes epidemiologiques.",
        'en'=>'This platform is used for data collection, daily monitoring, preliminary analysis, and trend detection. Data is then exported as CSV and imported into SPSS (or R) for the in-depth final analysis presented in the Results chapter. This dual approach (digital platform + statistical software) is the one adopted by major epidemiological studies.'
    ],
