/**
 * Fonction de traduction principale
 * Utilisation: __('key') ou __('key', $lang)
 */
function __($key, $forceLang = null) {
    global $t, $lang;
    $l = $forceLang ?? $lang;
    return $t[$key][$l] ?? $t[$key]['fr'] ?? $key;
}

/**
 * Retourne la direction CSS selon la langue
 */
function langDir() {
    global $dir;
    return $dir;
}

/**
 * Retourne le code langue courant
 */
function currentLang() {
    global $lang;
    return $lang;
}